UPDATE volunteer
real_name = #{realName}, gender = #{gender}, phone = #{phone}, email = #{email}, id_card = #{idCard}, avatar = #{avatar}, province = #{province}, city = #{city}, district = #{district}, detailed_address = #{detailedAddress}, latitude = #{latitude}, longitude = #{longitude}, certification_status = #{certificationStatus}, wallet_address = #{walletAddress}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT id, username, password, real_name as realName, gender, phone, email, id_card as idCard, avatar, province, city, district, detailed_address as detailedAddress, latitude, longitude, total_hours as totalHours, points, certification_status as certificationStatus, wallet_address as walletAddress, status, create_time as createdAt, update_time as updateTime 
FROM volunteer 
WHERE wallet_address = #{walletAddress}

SELECT * FROM volunteer 
ORDER BY points DESC 
LIMIT #{limit}
